      "schema": {
        "properties": {
          "image_type": { "title": "Image_Type", "type": "string", "description": "type of image" },
          "short_description": { "title": "Short_Description", "type": "string", "description": "short description" },
          "summary": { "title": "Summary", "type": "string", "description": "summary of the image" }
        },
        "required": ["image_type","short_description","summary"],
        "title": "BBOXAnnotation",
        "type": "object",
        "additionalProperties": false
      },
      "name": "bbox_annotation",
      "strict": true
    }
  },
  "include_image_base64": true
}

